// Covariance — produce T
interface Producer<out T> { fun produce(): T }
val dogs: Producer<Dog> = object : Producer<Dog> { override fun produce() = Dog() }
val animals: Producer<Animal> = dogs   // ✅ covariant

// Contravariance — consume T
interface Consumer<in T> { fun consume(value: T) }
val anyAnimal: Consumer<Animal> = object : Consumer<Animal> { override fun consume(value: Animal) = Unit }
val dogConsumer: Consumer<Dog> = anyAnimal  // ✅ contravariant

