// Custom delegate — preference-backed property (Android idiom)
class PrefDelegate(val prefs: SharedPreferences, val key: String, val default: String) : ReadWriteProperty<Any?, String> {
  override fun getValue(thisRef: Any?, property: KProperty<*>): String =
    prefs.getString(key, default) ?: default
  override fun setValue(thisRef: Any?, property: KProperty<*>, value: String) {
    prefs.edit().putString(key, value).apply()
  }
}

class AppPrefs(prefs: SharedPreferences) {
  var theme: String by PrefDelegate(prefs, "theme", "system")
}

@DslMarker
annotation class HtmlDsl

@HtmlDsl
class Html { val children = mutableListOf<Tag>() }

@HtmlDsl
open class Tag(val name: String) {
  val children = mutableListOf<Tag>()
  var text: String? = null
  override fun toString(): String {
    val inner = (text ?: "") + children.joinToString("")
    return "<\$name>\$inner</\$name>"
  }
}

fun html(block: Html.() -> Unit): Html = Html().apply(block)

fun Html.body(block: Tag.() -> Unit) {
  val t = Tag("body").apply(block)
  children += t
}
fun Tag.h1(text: String) { children += Tag("h1").apply { this.text = text } }
fun Tag.p(block: Tag.() -> Unit) { children += Tag("p").apply(block) }
fun Tag.text(s: String) { text = s }

// Usage — looks declarative
val page = html {
  body {
    h1("Hello")
    p {
      text("Lorem ipsum")
    }
  }
}
println(page.children.joinToString("")) // <body><h1>Hello</h1><p>Lorem ipsum</p></body>

