// Function aliases shine for callback-heavy code
typealias Validator<T> = (T) -> Result<Unit>

fun <T> validate(value: T, vararg rules: Validator<T>): Result<Unit> {
  for (r in rules) r(value).onFailure { return Result.failure(it) }
  return Result.success(Unit)
}

val emailValid: Validator<String> = { s -> if ("@" in s) Result.success(Unit) else Result.failure(IllegalArgumentException("bad")) }

